"""
MKT Context Commentary — Proverbs chapters 25–27
Run: python3 scripts/zc-context-proverbs-25-27.py

Source data used:
- data/interlinear/proverbs.json
- data/translation/notes/proverbs.json
- data/translation/draft/mediating/proverbs.json (MKT text)

Key context decisions:
- 25:1 (Hezekiah superscription) is given expanded treatment as the single most
  important historical datum in Proverbs for understanding the book's editorial
  history and Judean scribal culture.
- The "burning coals" (25:22) debate is presented fairly: both the Egyptian
  penitence-ritual reading and the shame-induction reading are noted.
- Ch. 26's fool-portrait (vv. 1–12) is treated as a literary unit — the most
  concentrated taxonomy of foolishness in the book.
- The apparent contradiction at 26:4–5 is explained as situational wisdom, not
  textual error.
- The agricultural poem (27:23–27) is noted as the wisdom tradition's unusual
  grounding of theological instruction in pastoral economics.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "25": {
    "1": '<p>This superscription — "These also are proverbs of Solomon, which the men of Hezekiah king of Judah copied" — is the single most important historical datum in the book for understanding its editorial formation. Hezekiah\'s reign (c. 715–687 BCE) was a period of religious and cultural reform in Judah, paralleling what 2 Kgs 18–20 and 2 Chr 29–32 describe as a deliberate restoration of Davidic-Solomonic traditions. The Hebrew verb <em>ʿāṯaq</em> (copied, transcribed, moved) implies the scribal activity of transmission — palace scribes (<em>ʾanšê ḥizqiyyāhû</em>, the men of Hezekiah) working deliberately to preserve and transmit a Solomonic literary heritage. This places the formation of the book of Proverbs within the royal scribal culture of Jerusalem, likely in connection with the broader Hezekian reform that also produced significant theological activity (cf. the arrangement of Isaiah\'s scroll). Chapters 25–29 are thus the "Hezekian appendix" to the main Solomonic collection of chapters 10–22.</p>',
    "2": '<p>"It is the glory of God to conceal things, but the glory of kings is to search them out" — the contrast between divine concealment and royal investigation frames the entire court-wisdom section of chapter 25 (vv. 2–7). In ancient Near Eastern royal ideology, kings were expected to be wise, discerning, and investigative — the Mesopotamian ideal of the wise king who "searches out hidden things" (cf. the Gilgamesh prologue\'s claim that he "saw the deep") finds its Israelite counterpart here. The theological point is subtle: God\'s glory is in withholding what he knows; the king\'s glory is in approximating divine knowledge through investigation. Both point to the same cognitive landscape — the hidden wisdom of the Creator.</p>',
    "3": '<p>"As the heavens are high and the earth is deep, so the heart of kings is unsearchable" — the spatial comparison (heavens/earth) to the psychic depths of the king\'s inner life uses ancient cosmological measurement as a standard of immeasurability. In ancient Near Eastern royal inscriptions, the king\'s wisdom and heart were frequently compared to cosmic realities. The "unsearchable heart" (<em>ḥēqer lēb məlākîm</em>) places the king\'s inner life beyond ordinary scrutiny — a realistic observation about court culture where the monarch\'s true intentions were politically dangerous to question. The wise courtier of vv. 6–7 operates precisely in this environment of opacity.</p>',
    "4": '<p>"Remove dross from the silver, and a vessel emerges fit for the silversmith" — the metallurgical simile draws on a well-attested ancient technology. Silver smelting in Iron Age Israel (the Timna and other sites) involved repeated heating to separate the base metal impurities (<em>sîgîm</em>, dross, slag) from the refined product. The process was commonly known and visible in any craft market. The simile bridges directly to v. 5: just as the smith removes impurities to produce fine silver, the king who removes the wicked from his court produces a just throne. The purification metaphor applies to political governance the logic of artisanal craft.</p>',
    "5": '<p>"Remove the wicked from before the king, and his throne will be established in righteousness" — court ethics in ancient Israel paralleled the concerns of ancient Near Eastern wisdom texts about the danger of corrupt advisors. The Egyptian <em>Instruction for Merikare</em> warns against listening to false counselors; Mesopotamian wisdom texts similarly advise the king to surround himself with righteous men. The practical sociology of ancient courts — where access to the king determined policy — makes this proverb operationally significant: corrupt advisors corrupt governance at its source. <em>Yikkôn bāṣedeq</em> (will be established in righteousness) — righteous rule is the structural outcome of a purified court.</p>',
    "6": '<p>"Do not exalt yourself in the king\'s presence, and do not stand in the place of the great" — court etiquette in ancient Israel and the broader ancient Near East was highly codified. Standing near the king in inappropriate proximity was a political and social infraction; seating arrangements in royal court audiences communicated hierarchy. The wisdom here is not mere politeness but strategic social intelligence: self-promotion in the royal presence backfires. The same principle appears in Jesus\'s parable of banquet seats (Luke 14:7–11), which directly cites vv. 6–7 as its Old Testament precedent.</p>',
    "7": '<p>"For it is better that someone say to you, \'Come up here,\' than that you be put lower before a noble" — the honor-shame dynamics of ancient Mediterranean social culture are fully operative here. Public demotion before the noble assembly was a maximum humiliation; being invited upward was the supreme social honor. The proverb teaches deliberate self-lowering as the only safe strategy in hierarchical court settings. The principle operates in virtually all ancient Near Eastern court cultures and appears in Egyptian wisdom (<em>Instruction of Ptahhotep</em>: "Do not be proud of your knowledge") as well as the NT (Jas 4:10; Matt 23:12).</p>',
    "8": '<p>"Do not rush into a dispute, lest you do not know what to do when your neighbor shames you in the end" — legal disputes at the city gate were public spectacles; losing one brought lasting reputational damage. The warning against hasty litigation reflects the reality of ancient Israelite legal culture, where cases were adjudicated by community elders and outcomes were publicly visible. "Rushing" into a dispute without adequate preparation was strategically foolish; the experienced litigant prepared carefully. The proverb teaches legal prudence as a form of social self-preservation.</p>',
    "9": '<p>"Argue your case directly with your neighbor, and do not disclose another\'s secret" — the two commands are connected: direct dispute resolution avoids the gossipy escalation that comes from broadcasting a neighbor\'s secrets while making your case. <em>Rîb rîbəkā ʾet-rēʿekā</em> (argue your case with your neighbor) favors bilateral resolution over public litigation when possible — a principle also in the Mosaic law\'s provision for dispute resolution and later rabbinic tradition\'s preference for compromise (<em>pesharah</em>). Disclosing confidences in the course of a dispute weaponizes private knowledge, escalating the conflict beyond repair.</p>',
    "10": '<p>"Lest one who hears it reproach you, and your ill repute never depart" — reputational damage in ancient Israel\'s village and town culture was virtually permanent. The community was the audience for all social transactions; the city gate was the bulletin board of collective memory. A person known for revealing secrets lost the trust that was the currency of all social relations — business partnerships, marriage arrangements, legal testimony. The proverb\'s "never depart" (<em>lō tāšûb</em>, will not return) reflects the lived reality of small-scale social worlds where reputation was nearly impossible to rehabilitate once damaged.</p>',
    "11": '<p>"A word spoken at the right moment is like golden apples set in silver" — <em>dābār dābûr ʿal-ʾopənāyw</em> (a word spoken on its turning points/at the right moment) — the key phrase is <em>ʾōpen</em> (its circumstances, its proper conditions) — timing as the crucial variable in wisdom speech. The comparison to golden apples (<em>tappûḥê zāhāb</em>) in silver settings brings together aesthetic beauty and material value; the image has been interpreted as decorative metalwork (a golden bowl in a silver setting) or as the naturally occurring color contrast of orange citrus fruit in a silver dish. Either way: timely speech combines rarity, beauty, and value in a single moment.</p>',
    "12": '<p>"Like a gold earring and an ornament of fine gold is a wise reprover to an obedient ear" — the jewelry comparison (gold earring, fine gold ornament) applies to the act of giving and receiving rebuke what the previous verse applied to timely speech. Both are acts of aesthetic and relational value that require skilled craftsmanship — the reprover must be wise; the ear must be obedient. The ear (<em>ʾōzen šomaʿat</em>, the listening/obeying ear) is explicitly the subject: a wise word given to a closed ear is no ornament at all. Wisdom\'s rebuke-gift is only received by the prepared recipient.</p>',
    "13": '<p>"Like the coolness of snow at harvest time is a faithful messenger to those who send him; he refreshes the spirit of his masters" — "snow at harvest time" is paradoxical: harvesting in Israel (typically May–June in the lower elevations) is hot and dry; snow would be deeply out of place. The image draws on the practice of bringing ice or snow from the mountains (Lebanon, Hermon) to cool summer drinks for the wealthy (cf. Prov 31:21\'s mention of snow). The impossible coolness of snow in summer heat = the miraculous relief of a reliable report in a tense commercial or political situation. The faithful messenger was economically critical in a world without rapid communication.</p>',
    "14": '<p>"Like clouds and wind without rain is one who boasts of a gift he never gives" — the meteorological simile is acute for Palestine\'s climate. Clouds building over the Mediterranean in the dry season, driven by wind, would raise expectations of rain — relief from the summer drought — that then fail to materialize. This agricultural disappointment maps perfectly onto the social disappointment of the false giver: impressive appearance, no substance. The "gift" (<em>maṭṭān šeqer</em>, a lie/false gift) is the verbal promise of generosity that the community holds in expectation — and which never materializes.</p>',
    "15": '<p>"By patience a ruler is persuaded, and a soft tongue can break a bone" — the paradox of gentle speech breaking bone is the proverb\'s most striking image. <em>ʾerek ʾappayim</em> (patience, literally "long of nostrils") — the nose is the organ of anger in Hebrew idiom; a long nose means slow to anger, patient. The "soft tongue" (<em>lāšôn rakkâ</em>) that breaks bone (<em>gārem</em>) captures the principle that persistent, measured, gracious speech is ultimately more effective than forceful confrontation in the face of power — especially royal power. Ancient court culture required mastering this art; direct confrontation of a ruler was dangerous.</p>',
    "16": '<p>"If you find honey, eat only enough for yourself, lest you have too much and vomit it" — honey in ancient Israel was a genuine luxury, available from wild hives and later from kept bees; it was the primary sweetener in a pre-sugar economy. The command to self-limit honey consumption is simultaneously a dietary caution and a social principle: the same restraint applies to all good things that tempt excess. The warning about vomiting (physical consequence of overconsumption) is followed directly in v. 17 by the social consequence of overconsumption of a neighbor\'s hospitality — the parallelism makes the point: moderate your appetite in all domains.</p>',
    "17": '<p>"Keep your foot rare in your neighbor\'s house, lest he have his fill of you and come to hate you" — the phrase "keep your foot rare" (<em>hōqar raglekā</em>) is unusual: <em>yāqar</em> (rare, precious, valuable) applied to foot visits means: make your visits scarce so they remain valuable. This is practical social wisdom about the economics of social capital: over-presence depletes the goodwill that scarcity would sustain. The neighbor\'s satiation and hatred is the outcome of social overstaying — the host who initially welcomed becomes annoyed through excess. The hospitality culture of ancient Israel had strong norms about both offering and receiving guest-welcome appropriately.</p>',
    "18": '<p>"A man who testifies falsely against his neighbor is a club, a sword, and a sharp arrow" — three weapons of increasing range (close combat club, thrusting sword, long-range arrow) are applied to false witness. The legal context is the city-gate court where testimony determined outcomes that could include property loss, exile, or death (cf. Deut 19:16–21 on the false witness). False testimony is violence by another means — it does the same bodily damage as physical weapons but through the juridical system. The three-weapon enumeration emphasizes that false witness is not a minor social infraction but an act of lethal aggression against a neighbor.</p>',
    "19": '<p>"Trusting an unreliable person in a time of trouble is like a broken tooth or a lame foot" — "a time of trouble" (<em>yôm ṣārâ</em>, day of distress) is the moment when reliability matters most; the person who fails then fails catastrophically. A broken tooth and a lame foot are apt: both fail precisely at the moment they are needed for their function (eating, walking); the failure is not merely inconvenient but actively painful and incapacitating. The unreliable person in crisis is the social equivalent of a disabled organ — structurally present but functionally absent at the worst possible moment.</p>',
    "20": '<p>"Like one who takes away a garment in cold weather, and like vinegar poured on soda, is one who sings songs to a troubled heart" — the taking of a garment in cold weather is a legal injustice (Exod 22:25–27; Deut 24:12–13 protect the cloak of the poor as their bedding); applied here to cheerful singing to a grieving person, it characterizes forced jollity as a removal of something the sufferer needs. The vinegar-on-soda reaction (<em>neter</em> is natron, the alkaline mineral used as soap and leavening) creates an energetic, useless fizz — matching the social outcome of inappropriate cheerfulness: noise and dissolution without substance. Both images capture mismatch between context and response.</p>',
    "21": '<p>"If your enemy is hungry, give him bread to eat; if he is thirsty, give him water to drink" — the command to feed and water an enemy is one of Proverbs\' most striking ethical demands. In ancient Israel\'s honor-shame culture, providing food and water was the foundational act of hospitality — it created a social bond and implied a temporary cessation of hostility. The enemy (<em>śōnəʾakā</em>, the one who hates you) is still a member of the human community with basic biological needs; responding to those needs with provision rather than exploitation is the wisdom tradition\'s ethic of restrained power. Paul cites this verse in Rom 12:20 as the basis for his theology of non-retaliation.</p>',
    "22": '<p>"For you will heap burning coals on his head, and the LORD will reward you" — the "burning coals on the head" (<em>geḥālîm ʾatteh ḥōṯeh ʿal-rōʾšô</em>) is one of the most debated images in Proverbs. Two main interpretations have currency: (1) An Egyptian penitence ritual in which a guilty person carried a basin of burning coals on the head as a public demonstration of remorse — Proverbs\' promise would then mean that your generosity provokes your enemy\'s public shame-acknowledgment of wrongdoing; (2) the burning coals cause intense discomfort (shame and remorse) in the enemy\'s conscience. Either reading yields the same practical conclusion: generosity toward an enemy is the most effective means of moral victory, since it activates conscience rather than escalating aggression. The LORD\'s reward is the providential bonus that removes the need for personal vengeance.</p>',
    "23": '<p>"The north wind brings rain, and a scowling face drives away a slanderer" — meteorological observation applied to social dynamics: in the Mediterranean climate of Israel, the prevailing north and northwest winds bring moisture off the sea; the north wind (<em>rûaḥ ṣāpôn</em>) is the harbinger of rain in Palestinian agriculture. The scowling face (<em>ûpānîm nizʿāmîm</em>, indignant countenance) is the social equivalent: a clearly expressed, visible disapproval of slander stops it by removing the audience reaction that sustains it. Gossip requires a receptive audience; signal visibly that the audience is not receptive, and the gossip has no purchase.</p>',
    "24": '<p>"Better to live in a corner of the roof than with a quarrelsome wife in a spacious house" — this proverb (identical to 21:9) reflects the domestic architecture of Iron Age Israel, where flat-roofed houses had accessible roof space used for sleeping, drying goods, and leisure. The roof corner is exposed, small, and isolated — but the proverb rates it higher than a large shared dwelling if that dwelling contains constant contention. The ancient Israelite household (with extended family, animals in lower areas, and multiple generations sharing space) was intensely communal; a quarrelsome member in the shared spaces made the entire physical environment oppressive.</p>',
    "25": '<p>"Like cold water to a thirsty soul is good news from a distant land" — the physiological immediacy of cold water for a thirsty person (<em>nepheš ʿāyēpâ</em>, a weary/thirsty soul) is the basis for the comparison. In hot summer Palestine, access to cold water was itself a luxury — springs and shaded cisterns provided cool water; desert travel generated genuine mortal thirst. "Good news from a distant land" (<em>šəmuʿâ ṭôbâ mēʾereṣ merhāq</em>) is significant in a world where information traveled at walking pace; news from a distant region was inherently weeks old and potentially unreliable. "Good" news that arrives intact is as refreshing as cold water in a dry land.</p>',
    "26": '<p>"A righteous man who gives way before the wicked is like a muddied spring and a polluted well" — the water imagery continues from v. 25. Clean water sources (springs and wells) were critical infrastructure in ancient Palestine; a contaminated water source threatened the entire community\'s survival. The righteous person (<em>ṣaddîq</em>) who yields to the wicked — through compromise, fear, or corruption — becomes a contamination of the very resource the community depends on. The civic and judicial role of righteous leaders in ancient Israelite communities was as essential as clean water; moral capitulation by the righteous has the same systemic effect as pollution of the water supply.</p>',
    "27": '<p>"It is not good to eat too much honey, nor is it glorious to seek your own glory" — the honey-excess warning of v. 16 recurs in modified form; this time paired with self-glorification. The two excesses are structurally parallel: physical overconsumption of sweetness and social overconsumption of honor both produce a kind of nausea (physical or social). Self-glory seeking (<em>ḥēqer kəbōdām kābôd</em>, to search out one\'s own glory is glory) is grammatically ironic — using "glory" (<em>kābôd</em>) twice in a sentence that denies self-glorification. The Hezekian collection that began in v. 1 with the kings who "search things out" ends here by forbidding the search for one\'s own honor: investigation of the world is glorious; investigation of the self for self-aggrandizement is not.</p>',
    "28": '<p>"A man with no control over his spirit is like a city that is broken down and without walls" — the city wall (<em>ḥômâ</em>) was the primary defensive infrastructure of ancient Israelite cities; a city without walls was militarily indefensible, open to any enemy that approached. Applied to the human self, "no control over his spirit" (<em>ʾên maʿṣōr lərûḥô</em>) — no restraint over the animating inner force — produces the same vulnerability. The self without self-control is topographically open: every impulse, temptation, and external pressure enters without resistance. The urban-defensive metaphor for self-discipline appears in parallel wisdom traditions; the inner life is a city requiring protection from the chaos of unregulated passions.</p>'
  },
  "26": {
    "1": '<p>Chapter 26 opens the most concentrated fool-portrait in the book of Proverbs (vv. 1–12), a literary unit unified by repeated references to the <em>kəsîl</em> (fool) or <em>ʾĕwîl</em> (morally thick-headed person). "Like snow in summer or rain at harvest, so honor is out of place for a fool" — snow in Palestinian summer and rain at grain harvest (May–June) are both seasonal impossibilities — they would damage the crops rather than sustain them. Honor given to a fool is equally dissonant with the moral order: it mismatches recipient with reward, creating systemic disorder. The agricultural metaphors throughout the fool-section reflect the Israelite wisdom tradition\'s grounding in seasonal patterns as moral analogies.</p>',
    "2": '<p>"Like a fluttering sparrow or a darting swallow, a causeless curse does not land" — the bird-in-flight images capture movement that goes nowhere productive: birds that fly without settling. A curse without cause (<em>qillēlat ḥinnām</em>, a groundless curse) is similarly without traction. In the ancient Near Eastern world, curses were understood to have genuine power to bind and harm; the proverb\'s reassurance is that a curse requires moral grounds to "land" — it must be justified to find its target. The language of magical speech having weight and direction (like a projectile) is shared across the ancient world; here wisdom demystifies it: groundless cursing is the sparrow that circles without roosting.</p>',
    "3": '<p>"A whip is for the horse, a bridle for the donkey, and a rod for the back of fools" — the three-part catalogue matches correction instrument to creature requiring it. In ancient Israel\'s agricultural economy, the horse (primarily military), the donkey (the primary work animal), and the human fool were each governed by an appropriate instrument. The rod (<em>šēbeṭ</em>) applied to fools\' backs is not gratuitous violence but the folk-wisdom equivalent of behavioral correction through physical consequence — paralleling the proverbial use of the rod for children (13:24; 22:15; 23:13–14). The proverb implicitly compares fools to work animals requiring external control because they lack internal self-direction.</p>',
    "4": '<p>"Do not answer a fool according to his folly, lest you become like him" — verses 4–5 are deliberately juxtaposed in apparent contradiction, and have been recognized as such since antiquity (the Talmud identifies them as a pair that almost caused the book to be excluded from the canon). The command here is: do not engage with folly on its own terms, because doing so drags you down to the fool\'s level. The social wisdom: some arguments are not worth having; engaging with bad-faith or foolish rhetoric produces only more bad-faith rhetoric. Context determines whether silence or engagement is wiser — and wisdom consists precisely in reading context correctly.</p>',
    "5": '<p>"Answer a fool according to his folly, lest he think himself wise" — the counter-command: sometimes silence permits the fool to go unchallenged, and unchallenged foolishness proliferates. The context that calls for engagement is when the fool\'s claim is dangerous and left unchallenged will damage others or become entrenched. The two proverbs together constitute situational wisdom: the reader must determine which case they are in. This is a model of wisdom\'s epistemological maturity — the tradition does not give a universal rule but trains the reader to discern between contexts requiring different responses. The juxtaposition is pedagogically intentional, not an editorial accident.</p>',
    "6": '<p>"Whoever sends a message by the hand of a fool cuts off his own feet and drinks violence" — in the pre-literate and slow-communication world of ancient Israel, messengers (<em>malʾākîm</em>) were the bearers of critical information between parties who could not meet; the reliable messenger was strategically essential. Sending a fool as messenger is self-sabotage: "cuts off his own feet" (<em>qōṣēṣ raglayyim</em>) — amputates his own means of travel, of reaching his destination. "Drinks violence" (<em>šōṯeh ḥāmās</em>) — violence swallowed, self-inflicted harm drunk as if it were sustenance. The sender who dispatches a fool receives the fool\'s incompetence back as his own injury.</p>',
    "7": '<p>"Like the limp legs of a lame man is a proverb in the mouth of a fool" — the physical disability analogy is precise: legs exist to walk; wisdom-sayings exist to guide action. A lame person\'s legs fail to perform their function; they are present but non-operative. A wise saying in the mouth of a fool is equally non-operative — present, but detached from the wisdom that makes it functional. The fool can quote wisdom; he cannot enact it, because enactment requires the formative orientation that the fool lacks. The proverb points to the gap between verbal wisdom-possession and embodied wisdom-practice.</p>',
    "8": '<p>"Like one who binds a stone in a sling is one who gives honor to a fool" — the sling (<em>qelaʿ</em>) was the primary ranged weapon of ancient Israelite warfare and shepherding (cf. David\'s sling, 1 Sam 17:40); it worked by centrifugal force to propel the stone at release. Binding the stone in the sling so it cannot be released defeats the entire purpose of the weapon — the stone goes nowhere. Honor given to a fool is similarly misdirected: a resource (social honor) deployed in a way that cannot achieve its purpose. The fool cannot receive honor effectively, just as the bound stone cannot achieve velocity.</p>',
    "9": '<p>"Like a thorn that goes into a drunkard\'s hand is a proverb in the mouth of fools" — the drunkard who grasps a thorn-branch cannot feel the pain that would warn a sober person to release it; he holds on to something that damages him without sensing the damage. A proverb held by the fool similarly damages those around him without the fool sensing the harm he causes. The drunkard\'s insensibility (anesthetic intoxication) maps onto the fool\'s moral insensibility — both are immune to the normal feedback mechanisms (pain, shame) that would correct ordinary behavior. The dangerous proverb-in-fools-hand echoes v. 7\'s limp legs but adds the dimension of active harm rather than mere non-function.</p>',
    "10": '<p>"Like an archer who wounds everyone is one who hires a fool or any passerby" — the undiscriminating archer who hits bystanders rather than targets is the image for the employer who hires without discernment. In ancient Israel\'s labor economy, hiring arrangements for agricultural, craft, or domestic work were common but short-term; the danger of hiring a fool or a random passerby was real. The proverb counsels selective employment as a form of social self-protection: indiscriminate hiring is indiscriminate harm-creation, like archery without aim. The employer bears responsibility for the fool\'s actions once the employment relationship is established.</p>',
    "11": '<p>"Like a dog that returns to its vomit is a fool who repeats his folly" — the disgust-inducing animal image is chosen for maximum impact; the dog was a scavenger in ancient Israel, not a pet, and canine behavior was associated with shamelessness (cf. 1 Sam 17:43; 2 Kgs 9:36). The fool who returns to his folly after experiencing its consequences mirrors the dog\'s return to its vomit — both repeat the self-harming cycle despite the evidence of its damage. The apostle Peter cites this proverb in 2 Pet 2:22 to describe apostates who return to pre-conversion sin. The image\'s power lies in its visceral clarity: there is no rational explanation for the return, which is why it characterizes foolishness rather than mere error.</p>',
    "12": '<p>"Do you see a man wise in his own eyes? There is more hope for a fool than for him" — the paradox closes the fool-collection: the self-convinced wise person is worse than the fool. The fool (<em>kəsîl</em>) at least does not deceive himself about his wisdom; the person who is "wise in his own eyes" (<em>ḥākām bəʿênāyw</em>) has compounded foolishness with self-deception, closing off any possibility of learning. This is the Socratic insight in Israelite dress: the beginning of wisdom is knowing one does not have it. The person who already thinks himself wise has no starting point for genuine formation. The collection ends not with the worst fool but with the most dangerous form of wisdom-failure: self-congratulatory delusion.</p>',
    "13": '<p>"The slothful man says, \'There is a lion in the road; there is a lion in the streets.\'" — this near-duplicate of 22:13 is placed in the sluggard mini-collection of vv. 13–16. The repetition is deliberate: Proverbs\' collections frequently repeat proverbs across contexts (cf. 18:8 = 26:22 on the gossip). The lion excuse — implausible enough in any settled Israelite town, absurd on a city street — captures the sluggard\'s characteristic inflation of obstacles. Real lions were occasionally encountered outside cities; invoking one as a street hazard is comic exaggeration. The sluggard\'s obstacle-imagination always exceeds reality by exactly the amount needed to justify inaction.</p>',
    "14": '<p>"As a door turns on its hinges, so a sluggard turns on his bed" — the hinge (<em>ṣîr</em>) is the pivot-point of a door; it moves, but going nowhere. The sluggard\'s turning on the bed has exactly the same quality: motion without translation, activity without progress. Ancient Israelite doors used stone or metal pivot pins in sockets; the analogy was visible daily. The image captures the sluggard\'s paradox — not completely inert, but all movement is lateral, circular, within the boundary of the bed. This is one of Proverbs\' most precise physical comedy images: the door-hinge and the turning sleeper are kinematically identical.</p>',
    "15": '<p>"The sluggard buries his hand in the dish; it is too much effort for him to bring it back to his mouth" — the exaggeration of torpor reaches its comic peak here. The communal dish at an ancient Israelite meal (<em>ṣallaḥat</em>, a large serving bowl) was reached into with the hand; raising it to the mouth was the simplest possible act of self-feeding. The sluggard cannot complete even this minimal effort. The image is so extreme it functions as satirical hyperbole — a reductio ad absurdum of the principle that the slothful person eventually becomes unable to perform the minimum required for survival. Cf. the similar exaggeration in 19:24.</p>',
    "16": '<p>"The sluggard thinks himself wiser than seven who can give a sensible answer" — "seven" is the number of completeness: not literally seven advisors but all the advisors one could assemble. The sluggard\'s self-assessed wisdom exceeds the combined practical wisdom of any assembly of sensible people — which is the precise measure of his delusion. The connection to v. 12\'s person "wise in his own eyes" is direct: the sluggard is not merely lazy but epistemically sealed, unable to receive correction because he has already concluded he is right. The chapter moves from fool to sluggard because both share this self-sealing quality that makes wisdom-reception impossible.</p>',
    "17": '<p>"Like one who grabs a dog by the ears is whoever meddles in a quarrel that is not his own" — seizing a dog by the ears was a practical reality in ancient Israel where dogs were semi-wild scavengers: the animal would bite reflexively if grabbed in this way, and the person grabbing could not release without being bitten. The meddler in another\'s quarrel faces the same trap: having inserted himself into the conflict, he cannot extract himself without injury from one or both parties. The proverb reflects the social wisdom of ancient communities where extended-family and village disputes were complex webs of obligation; uninvited intervention routinely drew the intervener into liability they had not anticipated.</p>',
    "18": '<p>"Like a madman who throws firebrands, arrows, and death" — the three projectiles (firebrands, arrows, lethal implements) escalate from mischief through lethality; together they represent the full range of harm a violent, irrational person can inflict. The <em>miṯlahēah</em> (madman, one who behaves with reckless abandon) is the person who has lost the restraint that makes communal life possible; his weapons are deployed without aim or discrimination. The verse is incomplete without v. 19 — the comparison is suspended to heighten impact when the identification is finally made.</p>',
    "19": '<p>"So is the man who deceives his neighbor and then says, \'I was only joking.\'" — the suspended comparison completes: the madman throwing lethal projectiles = the man who deceives (<em>rimmâ</em>, to deceive, to beguile) and then retreats to the "just joking" (<em>hălōʾ məśaḥēq ʾānî</em>, am I not playing?) defense. The invocation of humor as a cover for deliberate harm is recognized as manipulative in wisdom tradition: the claim of joking retroactively converts a deliberate deception into a failed laugh. The social impact of deception is real regardless of the stated intention; the proverb holds the deceiver accountable for consequences he cannot retroactively re-categorize.</p>',
    "20": '<p>"Without wood, a fire goes out; without a gossip, a quarrel dies down" — the fuel metaphor for gossip (<em>nirgān</em>, whisperer, slanderer) identifies the social mechanism: conflict requires ongoing information-supply to sustain itself. Remove the gossip who keeps carrying and reshaping the narrative, and the quarrel loses its energy source. The fire analogy from practical household experience (wood management was real work in a deforested ancient landscape) maps precisely onto the sociology of gossip: the social fire of communal conflict burns exactly as long as it is fed by those who carry its fuel. This is one of Proverbs\' clearest statements of a social-systems principle.</p>',
    "21": '<p>"As charcoal to embers and wood to fire, so is a quarrelsome man in kindling strife" — the previous verse (wood removed → fire dies) is inverted: wood added to embers → fire intensifies. The quarrelsome man (<em>ʾîš midyānîm</em>, a man of quarrels/disputes) is the fuel-supplier who keeps conflict alight. The two verses together form a diptych: the gossip is the horizontal carrier (transporting fuel across relationships); the quarrelsome man is the vertical intensifier (adding fuel to the conflict itself). Both are identified as the structural causes of communal strife — remove them, and conflict cannot self-sustain.</p>',
    "22": '<p>"The words of a gossip are like delicacies; they go down into the inner chambers of the body" — identical to 18:8. The repetition across contexts (here in a section on social discord) is typical of the wisdom tradition\'s anthology method. The delicacy (<em>mitlahamîm</em>, dainties, things swallowed eagerly) captures gossip\'s appeal: it is consumed with pleasure and goes deep. "Inner chambers of the body" (<em>ḥadrê-bāṭen</em>, the inward rooms of the belly) — the deepest interior; gossip that is received becomes formative, shaping perception and memory from the inside. The verse identifies why gossip is so persistent: it is pleasurable to consume and deeply absorbing once received.</p>',
    "23": '<p>"Fervent lips paired with a wicked heart are like a clay pot glazed with silver dross" — the metallurgical image is of sophisticated surface deception: silver dross (<em>sîgîm</em>, the waste product of smelting) applied as a glaze to cheap earthenware (<em>ḥereś</em>) would look like real silver-ware from a distance. The technology was known in ancient Israel (thin silver overlays on ceramics exist in the archaeological record). Applied to human speech: burning enthusiasm (<em>śəpāṯayim dōlāqîm</em>, fervent/inflamed lips) covering a wicked heart is impressive-looking surface over valueless content — the social equivalent of plated fakery. The gap between affect and inner character is the chapter\'s central diagnostic concern.</p>',
    "24": '<p>"Whoever hates disguises it with his lips, while storing up deceit within himself" — the verb <em>yiššākēr</em> (disguises, is deceitful — from <em>nākar</em>, to recognize as different, to disguise) describes the deliberate performance of a persona that conceals true hatred. "Storing up deceit within himself" (<em>bəqirbô yāšît mirmâ</em>) — the verb <em>šît</em> (to put, place, establish) applied to deceit describes internal reserve-building: the hater accumulates a cache of deception that sustains the surface performance. In the communal economy of ancient Israel, where relationships were sustained by face-to-face interaction, reading facial and verbal cues was the primary social intelligence skill; the proverb teaches heightened scrutiny of those whose affability seems disconnected from substance.</p>',
    "25": '<p>"When he speaks graciously, do not believe him, for there are seven abominations in his heart" — the specific counter-instruction: gracious speech from this person should trigger distrust rather than reassurance. "Seven abominations" (<em>šebaʿ tôʿēbôt</em>) — the number of completeness applied to moral revulsion: his inner life is comprehensively abominable, even as his speech is gracious. <em>Tôʿēbâ</em> (abomination) is the cultic-ethical revulsion-category, normally applied to what God detests (15:8–9, 26; 16:5; 17:15). Its application here to the contents of the hypocrite\'s heart places his inner condition in the category of divine revulsion — not merely social bad faith but theological transgression.</p>',
    "26": '<p>"Though his hatred is covered by deception, his wickedness will be exposed before the assembly" — the section on the hidden hater closes with the promise of disclosure. "Before the assembly" (<em>biqhāl</em>, in the assembly, congregation) — the community gathered for legal proceedings, religious ceremony, or public deliberation was the forum in which all private matters eventually became public. The ancient community\'s transparency — everyone knew each other\'s affairs in the village and town setting — made long-term concealment extremely difficult. The proverb\'s promise is simultaneously sociological (hidden things surface in community life) and theological (God ensures disclosure; cf. Luke 12:2–3).</p>',
    "27": '<p>"Whoever digs a pit will fall into it, and whoever rolls a stone will have it roll back on them" — the principle of self-defeating harm appears across the wisdom traditions of the ancient Near East (cf. Ps 7:15–16; 9:15–16; Eccl 10:8; Sirach 27:25–27). Both images — digging a pit to trap someone, rolling a stone down to crush someone — describe deliberate harm-planning that reverses direction. The lex talionis principle (harm returns to its sender) is here expressed as a principle of moral physics: the energy of planned wickedness has a natural tendency to retroact on its planner. This was observable enough in community life to be formulated as a general law.</p>',
    "28": '<p>"A lying tongue hates those it hurts, and a flattering mouth works ruin" — the chapter that began with the fool\'s misplaced honor ends with the liar\'s structural hatred. "Hates those it hurts" (<em>yiśnāʾ dakkayw</em>, hates its crushed/afflicted ones) is a profound psychological observation: the liar does not merely use lies instrumentally but develops actual hatred for the people the lies damage — because their suffering testifies to the liar\'s culpability. The flatterer works ruin (<em>marhēlâ yipḥeh pî ḥālāq</em>) because flattery substitutes for truth in a relationship and ultimately undermines it. The chapter\'s consistent theme — surface and interior are disconnected in the fool, the hater, the flatterer — reaches its conclusion: disconnection always produces destruction.</p>'
  },
  "27": {
    "1": '<p>"Do not boast about tomorrow, for you do not know what a day may bring" — the limitation of human temporal knowledge is one of wisdom\'s most characteristic themes. <em>ʾal-tithalēl bəyôm māḥār</em> (do not boast about tomorrow) — <em>hālal</em> (to boast, praise) in the Hithpael; the self-congratulation about a future not yet secured. The ancient Israelite world operated with minimal certainty about tomorrow: weather, disease, political upheaval, and market fluctuation were all genuinely unpredictable. The proverb does not teach fatalism but epistemic humility: tomorrow belongs to God, not to the planner. Cf. Jas 4:13–15 which cites this principle directly.</p>',
    "2": '<p>"Let someone else praise you, and not your own mouth; a stranger, and not your own lips" — self-praise in the honor-shame culture of the ancient Near East was simultaneously common and suspect. Praise that comes from others is socially validated; self-praise is unvalidated assertion. The "stranger" (<em>zār</em>, outsider, someone without stake in flattering you) who praises is the most credible witness, precisely because he has no relational obligation to do so. Ancient Near Eastern wisdom texts similarly counsel against self-promotion; the Egyptian <em>Instruction of Amenemope</em> warns against boasting of one\'s accomplishments. In Israel\'s community culture, reputation was a social fact established by others\' speech, not one\'s own declaration.</p>',
    "3": '<p>"A stone is heavy and sand is a burden, but a fool\'s anger weighs more than both" — the graduated weight comparison uses physical experience (carrying stone; the exhaustion of carrying sand\'s distributed weight across a long distance) as a standard for the social weight of the fool\'s anger. Stone is discrete and heavy; sand is diffuse and cumulatively exhausting. The fool\'s anger combines both: it has the sudden impact of stone and the grinding persistence of sand — and exceeds both. In communal life, managing the emotional outbursts of a fool was one of the most exhausting social labors, without the compensating satisfaction of productive work.</p>',
    "4": '<p>"Wrath is cruel, and anger is overwhelming, but who can stand before envy?" — the three terms escalate: <em>ḥēmâ</em> (hot wrath, burning fury) → <em>šeṭep̄ ʾap̄</em> (flood of anger, inundating passion) → <em>qinʾâ</em> (envy, jealousy — the passion that cannot be satisfied by its object\'s destruction). Envy is presented as the worst because it is bottomless: wrath spends itself; anger subsides; envy has no natural terminus. The psychology of envy (desiring not just what another has but that they not have it) makes it the most consuming and socially destructive of the passions. The proverb\'s rhetorical question "who can stand before envy?" expects the answer: no one.</p>',
    "5": '<p>"Open rebuke is better than hidden love" — the paradox is intentional: hidden love (love that does not express itself through honest correction) is, despite its warmth, less valuable than open rebuke (correction that risks the relationship by telling the truth). The wisdom tradition consistently prioritizes formative honesty over comfortable silence; the friend who rebukes is doing more for you than the friend who loves in silence. In Israel\'s community life, where one\'s moral reputation and practical choices affected the entire social network, honest rebuke was a social good — a form of communal care that required courage from the rebuker and willingness from the rebuked.</p>',
    "6": '<p>"The wounds of a friend can be trusted, but an enemy\'s kisses are lavish and false" — the inversion of expected social signals: wounds (<em>peṣaʿîm</em>, physical injuries) from a friend are reliable (<em>neʾĕmānîm</em>, trustworthy, faithful) while an enemy\'s kisses (<em>nəšîqôt śōnēʾ</em>) are excessive and deceptive. The word <em>ʿātār</em> (lavish, excessive) used for the kisses implies performance rather than genuine affection. The cultural context: in ancient Israel, the kiss was a greeting of peace and covenant (cf. Judas\'s kiss, which precisely inverts friendship-kissing into betrayal). The proverb teaches reading beneath the surface of social gestures: pain from the trustworthy is more valuable than pleasure from the hostile.</p>',
    "7": '<p>"One who is full despises honey, but to the hungry person every bitter thing is sweet" — the physiological paradox is exact: a satiated person finds even the best food unappealing; a genuinely hungry person finds even poor food palatable. Applied broadly: abundance dulls discernment (the prosperous person can afford to be selective); need sharpens appetite (the desperate person accepts what the comfortable reject). The proverb works as a warning against the spiritual torpor of prosperity — the well-fed person\'s contempt for honey is no compliment to his palate but a diagnosis of satiety. The hungry person\'s finding bitterness sweet is not a compliment to bitterness but testimony to genuine need.</p>',
    "8": '<p>"Like a bird that flees its nest, so is a man who wanders from his home" — the bird\'s nest was the natural habitat of its competence: birds build nests in specific locations suited to their biology and return to them reliably. A bird that has abandoned its nest is displaced, disoriented, exposed. The man who wanders from his home (<em>māqôm</em>, his place — the whole social-geographic setting of his household, kinship, and community) is equally displaced from his context of competence and care. In the ancient world, displacement from one\'s kin and community was a genuine existential threat; the proverb captures the vulnerability of the uprooted person.</p>',
    "9": '<p>"Oil and perfume bring joy to the heart; so does a friend\'s earnest counsel" — the two halves use the ancient healing and social-bonding properties of aromatic oils to characterize the value of trusted advice. Olive oil and imported perfumes were used in anointing, healing, and celebration throughout the ancient world; their scent was associated with festivity, comfort, and dignity (cf. Ps 23:5; Song 1:3). The friend\'s earnest counsel (<em>ʿēṣat rēaʿ minnepheš</em>, counsel from a friend from the soul/self) — advice given from one\'s deepest inner resource — has the same revitalizing quality as fragrant oil applied to the body.</p>',
    "10": '<p>"Do not forsake your friend or your father\'s friend; do not go to your brother\'s house in the day of your trouble. A neighbor who is near is better than a brother who is far away" — three social relationships are evaluated by proximity and reliability in crisis. The "father\'s friend" (<em>rēaʿ ʾābîkā</em>) is the longstanding relationship that spans generations — the trusted ally of the family\'s history. In the day of trouble (<em>yôm ʾêdekā</em>, day of calamity), geography of relationship matters: the physically near neighbor who can act immediately is more practically valuable than the biological brother who is geographically distant. Ancient Israelite social structure relied heavily on kinship networks; this proverb supplements biological kinship with earned and geographic proximity as valid foundations for crisis-support.</p>',
    "11": '<p>"Be wise, my son, and gladden my heart, so I may have a word for whoever taunts me" — the father-son address returns; the father\'s investment in the son\'s wisdom is explicitly social: his son\'s wisdom gives him something to say to those who mock him ("look what my son has become"). In ancient Israel\'s honor culture, a father was accountable for his son\'s formation; the son\'s wisdom was evidence of the father\'s competence as a parent and teacher. <em>Wəʾāšîbâ ḥōrəpî dābār</em> (I may answer my taunter a word) — the father\'s social standing in the community is at stake in the son\'s character.</p>',
    "12": '<p>"A prudent person sees danger and hides, but the simple walk on and suffer for it" — identical in substance to 22:3. The repetition signals a core wisdom principle about foresight: the prudent person\'s distinguishing capacity is anticipatory pattern-recognition — seeing danger (<em>rāʾâ rāʿâ</em>, seeing evil/danger) before it fully manifests and acting preemptively. The simple (<em>pətāʾîm</em>, the naive, the open) lack this anticipatory capacity; they respond only to immediate stimuli and suffer the consequences of delays in recognition. In the physical environment of ancient Israel (wild animals, seasonal flooding, bandits, crop failures), this foresight was genuinely life-saving.</p>',
    "13": '<p>"Take his garment when he has put up security for a stranger, and hold it in pledge when he does so for a wayward woman" — this verse (also at 20:16) addresses the practice of surety-giving (<em>ʿārēb</em>, to guarantee another\'s debt). Proverbs consistently warns against becoming security for a stranger (6:1–5; 11:15; 17:18; 22:26); here the creditor is advised to take a pledge (the guarantor\'s outer garment, the most essential item of clothing) immediately when the foolish surety arrangement is made. The "wayward woman" (<em>nokrîyyâ</em>, foreign/strange woman) echoes chapters 1–9; the man who gives surety for a strange woman has compromised himself doubly.</p>',
    "14": '<p>"Whoever blesses his neighbor with a loud voice early in the morning, it will be counted a curse to him" — the social comedy is precise: energetic, unsolicited, early-morning praise directed loudly at a neighbor is experienced as a nuisance rather than a blessing. Context determines the reception of speech acts; the same words ("blessings!") delivered at the wrong time and wrong volume produce the opposite of their intended effect. The proverb points to the wisdom of reading social situations before deploying speech, even positive speech. Ill-timed enthusiasm is socially indistinguishable from aggression — it violates the neighbor\'s morning peace with the same disruptive force as a curse.</p>',
    "15": '<p>"A constant dripping on a rainy day and a quarrelsome wife are alike" — the architectural context: ancient Israelite houses had flat or slightly pitched roofs of wooden beams, packed earth, and plaster that required maintenance; a poorly maintained roof dripped persistently during winter rains (<em>yôm sagrir</em>, day of downpour). The constant, unavoidable, wearing quality of the drip maps onto the persistent quarrelsomeness (<em>ʾēšet midyānîm</em>, woman of disputes) that cannot be escaped indoors. The comparison is not a general condemnation of women but a specific social observation about the particular domestic misery of inescapable conflict in the shared indoor space of a rainy season.</p>',
    "16": '<p>"Trying to restrain her is like trying to restrain the wind, and like trying to grasp oil in the right hand" — both images (restraining wind; grasping oil) are acts of impossible physical control: neither can be seized, contained, or stopped by direct force. Applied to the quarrelsome person\'s speech, the proverb is simultaneously frustrating and darkly funny: all the techniques of conflict de-escalation available in ancient household management were as effective as grabbing a handful of oil. The proverb counsels indirect approaches (or the roof-corner strategy of 25:24) rather than direct suppression.</p>',
    "17": '<p>"As iron sharpens iron, so one person sharpens another" — the metallurgical simile draws on the ubiquitous Iron Age technology of blade sharpening; iron tools (agricultural implements, weapons) required periodic sharpening against an iron file or whetstone. The friction between two metal surfaces produces the refinement of one. Applied to human intellectual and moral formation: substantive engagement between persons — genuine dialogue, honest challenge, intellectual friction — sharpens both parties. The proverb has become one of the most quoted in the Western tradition as a principle of mentorship, friendship, and intellectual community. In ancient Israel\'s wisdom schools and household education, this principle was lived practice.</p>',
    "18": '<p>"Whoever tends the fig tree will eat its fruit; whoever looks after his master will be honored" — the agricultural analogy grounds the social principle: the fig tree (<em>tēʾēnâ</em>) was one of Israel\'s most important fruit trees, requiring regular attention (pruning, pest management, harvesting) but yielding reliably to the diligent cultivator. Applied to the servant\'s relationship to the master: faithful attention to another\'s interests produces reliable return in honor and standing. The proverb reflects the hierarchical social structure of ancient Israel where skilled household service was a recognized and valued occupation; the trusted steward occupied an elevated position within the social order.</p>',
    "19": '<p>"As water reflects a face, so one person\'s heart reflects another\'s" — a still pool or water surface (in an era without manufactured mirrors) was the primary means of seeing one\'s own face. The comparison: just as water faithfully reflects the physical face that looks into it, so one person\'s inner life (<em>lēb</em>, heart) reflects another\'s. The interpretive options are rich: one reading is that our hearts are revealed by those around us (we see ourselves in others\' responses to us); another is that we find our own hearts in others (genuine friendship is mutual recognition). Either way, the proverb grounds self-knowledge in relational encounter rather than solitary introspection — a fundamentally social epistemology.</p>',
    "20": '<p>"Sheol and Abaddon are never satisfied; so the eyes of man are never satisfied" — <em>Šəʾôl</em> (the realm of the dead) and <em>ʾăbaddôn</em> (destruction, the abyss — cf. Rev 9:11 where it is personified as the angel of the abyss) are the two Hebrew names for the death-realm that is insatiably consuming. They "are not satisfied" (<em>lōʾ yiśbāʿû</em>) — the death-realm always receives more dead and never declares itself full. Applied to human eyes (<em>ʿênê hāʾādām</em>, the eyes of the human/Adam): visual appetite has the same bottomless quality. The connection between eye and covetousness runs through the wisdom tradition (6:25; Job 31:1); the eye that always wants to see more is a portal to insatiable desire that mirrors the underworld\'s insatiable reception of the dead.</p>',
    "21": '<p>"The crucible is for silver, and the furnace is for gold, and a man is tested by his praise" — the metallurgical testing process (crucible for silver, furnace for gold; cf. 17:3) authenticates the purity of a metal by subjecting it to heat that separates impurities. Applied to human character: praise is the testing heat that reveals what a person is made of. How one responds to being praised — whether with increased humility and gratitude or with inflated self-regard and complacency — reveals the quality of the character beneath the social surface. Praise is the social equivalent of the smelter\'s furnace: it brings to the surface what is really there.</p>',
    "22": '<p>"Even if you grind a fool in a mortar with a pestle amid grain, his folly will not leave him" — the mortar and pestle were the primary grain-processing instruments of ancient Israelite households; grinding was daily domestic labor. The extreme image — grinding a person in a mortar as one grinds grain — expresses the impossibility of forcing wisdom into the constitutionally foolish: no amount of corrective pressure, however radical, can extract the folly from a fool. The proverb is not a counsel of abandonment but a realistic statement about the limits of external intervention; character transformation requires internal orientation, which correction can prompt but not substitute for. Cf. 26:11 on the fool\'s compulsive return to folly.</p>',
    "23": '<p>"Know well the condition of your flocks, and give careful attention to your herds" — the agricultural poem of vv. 23–27 is unusual in Proverbs for its sustained practical-economic content; most wisdom sayings generalize from agriculture rather than address it directly. The command to "know well" (<em>yādōaʿ tēdaʿ</em>, infinitive absolute + imperfect for emphasis) the condition (<em>penê</em>, face, appearance, state) of one\'s flocks is a call to attentive, ongoing assessment rather than occasional oversight. Pastoral economies in ancient Israel (sheep and goat herding in the hill country and Negev) were the primary economic base for many households; the quality of the herder\'s attention directly determined family subsistence.</p>',
    "24": '<p>"For riches do not last forever; nor does the crown endure to all generations" — the theological rationale for pastoral attentiveness: accumulated financial wealth (<em>ḥōsen</em>, riches, stored resources) is inherently impermanent, subject to depletion; even royal dynasties (<em>keter</em>, crown) end. The productive capacity of well-managed flocks and herds provides a renewable resource base that outlasts accumulated capital. The contrast is between static wealth (stored money, which depletes) and dynamic biological productivity (flocks, which reproduce and renew). This is the wisdom tradition\'s version of productive capital versus consumption capital — a fundamentally agrarian economic theology.</p>',
    "25": '<p>"When the grass is gone and new growth appears and the mountain plants are gathered" — the seasonal agricultural cycle described here is specific to the Palestinian climate: the dry summer exhausts the grass; the early fall rains trigger new growth (<em>deše ʾ</em>, fresh green growth); mountain plants (<em>ʿăśab hārîm</em>, mountain vegetation) are harvested in late summer and fall. The three-stage cycle of grass depletion → regrowth → harvest describes the continuous provision of a well-managed pastoral year. The verse is transitional — it sets up the chain of provision in vv. 26–27.</p>',
    "26": '<p>"The lambs are for your clothing, and the goats supply the price of a field" — wool from sheep (<em>kəbāśîm</em>, lambs) provided the primary textile fiber for clothing throughout the ancient Near East; Israelite households wove their own garments from their flocks\' wool. Goats (<em>ʿizzîm</em>) provided milk, meat, and cash income through sale; the "price of a field" (<em>mǝḥîr śādeh</em>) could be paid from goat sales, enabling land acquisition that expanded the household\'s productive base. The pastoral economy is self-reinforcing: attentive herding → good flock → clothing (subsistence) + field price (capital expansion).</p>',
    "27": '<p>"There will be enough goats\' milk for your food, for the food of your household, and nourishment for your servant girls" — the poem closes with the sufficiency of the attentive farmer\'s household: goat\'s milk provides for the head of household, the extended family, and even the dependent servant girls (<em>naʿărôtêkā</em>). In ancient Israel, goat\'s milk was a dietary staple — consumed fresh, fermented as yogurt, and made into cheese. The poem concludes not with surplus or wealth but with <em>enough</em>: the pastoral economy, faithfully managed, produces comprehensive household sustenance. The "enough" is the wisdom tradition\'s vision of the good life: not abundance beyond need but reliable provision for all within the household economy.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-context', 'proverbs', existing)
    print('Proverbs 25–27 mkt-context written.')

if __name__ == '__main__':
    main()
